import { Flag, Eye, Target, Rocket, Landmark } from "lucide-react";
import { useEffect, useMemo, useRef, useState } from "react";
import AboutSection from "./NosotrosSection"; // Mantenemos la importación

// --- Estilos de Fuentes (del primer archivo) ---
const fontStyles = `
  @font-face {
    font-family: 'BodoniStd';
    src: url('/fonts/As_BodoniStd.otf') format('opentype');
    font-weight: normal;
    font-style: normal;
    font-display: swap;
  }

  @font-face {
    font-family: 'TrajanPro';
    src: url('/fonts/As_TrajanPro_Regular.ttf') format('truetype');
    font-weight: normal;
    font-style: normal;
    font-display: swap;
  }

  .font-bodoni {
    font-family: 'BodoniStd', serif;
  }

  .font-trajan {
    font-family: 'TrajanPro', serif;
  }
`;

// Insertar estilos en el head del documento
if (typeof document !== 'undefined') {
  const styleElement = document.createElement('style');
  if (!document.head.querySelector('#custom-font-styles')) {
    styleElement.id = 'custom-font-styles';
    styleElement.textContent = fontStyles;
    document.head.appendChild(styleElement);
  }
}

// --- Componente Principal ---
export default function AboutUsContainer() {
  // --- Contenido de la línea de tiempo (del primer archivo) ---
  const timelineData = useMemo(
    () => [
      {
        id: "seed",
        label: "2019",
        title: "La semilla de la idea",
        description:
          "Un grupo de historiadores y profesionales bolivianos identificó la necesidad de rescatar y ordenar la memoria empresarial del país.",
      },
      {
        id: "research",
        label: "2020",
        title: "Investigación y metodología",
        description:
          "Se definieron criterios curatoriales y una metodología rigurosa para garantizar veracidad y contexto histórico.",
      },
      {
        id: "pilot",
        label: "2021",
        title: "Proyecto piloto",
        description:
          "Un piloto con empresas de distintos rubros permitió validar el enfoque humano y técnico del proyecto.",
      },
      {
        id: "platform",
        label: "2022",
        title: "Nace la plataforma",
        description:
          "Construimos Orbis Empresarial como un espacio digital seguro, diseñado para preservar, inspirar y educar.",
      },
    ],
    [],
  );

  // --- Definición de secciones (combinando ambos archivos) ---
  const sections = useMemo(
    () => [
      {
        id: "about",
        title: "Sobre Orbis",
        Icon: Landmark,
        // Usaremos el componente importado para este cuerpo
        body: <AboutSection />,
      },
      {
        id: "objective",
        title: "Objetivo",
        Icon: Target,
        body: (
          <p className="font-trajan leading-relaxed">
            Reunir, organizar y difundir el legado de las empresas bolivianas,
            resaltando su impacto económico, social y cultural a lo largo del tiempo.
            Buscamos que cada historia sea accesible, confiable y significativa.
          </p>
        ),
      },
      {
        id: "mission",
        title: "Misión",
        Icon: Flag,
        body: (
          <p className="font-trajan leading-relaxed">
            Resguardar, documentar y compartir historias empresariales con un enfoque
            ético y profesional, promoviendo la cultura de archivo, la transparencia
            y el orgullo por el trabajo bien hecho.
          </p>
        ),
      },
      {
        id: "vision",
        title: "Visión",
        Icon: Eye,
        body: (
          <p className="font-trajan leading-relaxed">
            Convertirnos en el referente nacional de memoria empresarial, un puente
            entre generaciones que aporte a la identidad productiva del país y
            promueva una cultura de integridad y excelencia.
          </p>
        ),
      },
      {
        id: "origin",
        title: "Origen",
        Icon: Landmark,
        body: (
          <p className="font-trajan leading-relaxed">
            Nuestro proyecto nace de la convicción de que las empresas tienen
            historias que merecen ser contadas, no solo como registros económicos,
            sino como testimonios de perseverancia, innovación y contribución al
            desarrollo nacional.
          </p>
        ),
      },
      {
        id: "story",
        title: "Cómo empezó",
        Icon: Rocket,
        body: (
          <div className="w-full">
            <div className="relative overflow-x-auto md:overflow-visible px-2 py-6">
              <div className="absolute left-6 right-6 md:left-8 md:right-8 top-1/2 -translate-y-1/2 h-0.5 bg-[#F29E38]/50 rounded-full" />
              <ol className="relative z-10 flex min-w-[640px] md:min-w-0 items-start justify-between gap-10 md:gap-12 lg:gap-16 px-4 md:px-8 snap-x">
                {timelineData.map((item) => (
                  <li key={item.id} className="snap-center min-w-[160px]">
                    <div className="flex flex-col items-center text-center gap-3">
                      <div className="relative">
                        <span className="block w-3 h-3 rounded-full bg-[#F29E38] shadow-[0_0_0_6px_rgba(242,158,56,0.2)]" />
                      </div>
                      <div className="text-sm font-medium tracking-wide">
                        <span className="font-bodoni text-xl block">{item.label}</span>
                        <b className="font-trajan text-xs uppercase block mt-1">{item.title}</b>
                        <span className="font-trajan text-xs opacity-80 block max-w-[16rem] mt-1">{item.description}</span>
                      </div>
                    </div>
                  </li>
                ))}
              </ol>
            </div>
          </div>
        ),
      },
    ],
    [timelineData],
  );

  // --- Lógica de Hooks (en JavaScript) ---
  const [active, setActive] = useState(sections[0].id);
  const [visible, setVisible] = useState({});
  const refs = useRef({});

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          const id = entry.target.id;
          if (entry.isIntersecting) {
            setVisible((prev) => ({ ...prev, [id]: true }));
            setActive(id);
          }
        });
      },
      { root: null, threshold: 0.5, rootMargin: "-40% 0px -40% 0px" },
    );

    sections.forEach((s) => {
      const el = refs.current[s.id];
      if (el) observer.observe(el);
    });
    return () => observer.disconnect();
  }, [sections]);

  const scrollTo = (id) => {
    const el = refs.current[id];
    if (!el) return;
    el.scrollIntoView({ behavior: "smooth", block: "start" });
    setActive(id);
  };

  // --- Renderizado del Componente (JSX) ---
  return (
    <div className="min-h-screen bg-gray-50 text-[#072D42]">
      <main className="mx-auto max-w-[1400px] px-4 sm:px-6 lg:px-10 py-6 sm:py-10">
        
        {/* Navegación Móvil */}
        <div className="md:hidden sticky top-0 z-20 -mx-4 px-4 py-3 backdrop-blur bg-white/80 border-b border-gray-200">
          <div className="flex gap-3 overflow-x-auto pb-2 -mb-2 no-scrollbar">
            {sections.map((s) => (
              <button
                key={s.id}
                onClick={() => scrollTo(s.id)}
                className={`whitespace-nowrap rounded-full px-4 py-2 text-sm font-trajan tracking-wide transition-colors duration-300 ${
                  active === s.id
                    ? "text-white bg-[#072D42]"
                    : "text-[#072D42] bg-gray-200/80 hover:bg-[#072D42] hover:text-white"
                }`}
              >
                {s.title}
              </button>
            ))}
          </div>
        </div>

        {/* Layout de Escritorio */}
        <div className="grid md:grid-cols-[minmax(220px,18%)_1fr] gap-6 lg:gap-10">
          
          {/* Navegación Lateral Fija */}
          <aside className="hidden md:flex sticky top-6 h-[calc(100vh-3rem)] flex-col border-r border-gray-200 pr-6 lg:pr-8">
            <div>
              <h1 className="font-bodoni text-4xl lg:text-5xl text-[#072D42]">
                Orbis Empresarial
              </h1>
              <div className="mt-2 h-1 w-16 bg-[#F29E38] rounded-full" />
              <p className="mt-4 text-sm font-trajan text-[#072D42]/80">
                Preservando la historia viva de las empresas bolivianas.
              </p>

              <nav className="mt-8 flex flex-col gap-2">
                {sections.map((s) => (
                  <button
                    key={s.id}
                    onClick={() => scrollTo(s.id)}
                    className={`group text-left px-3 py-2 rounded-md transition-colors duration-300 ${
                      active === s.id
                        ? "bg-[#072D42]/10"
                        : "hover:bg-[#072D42]/5"
                    }`}
                  >
                    <span className="inline-flex items-center gap-3">
                      <span
                        className={`inline-block h-1.5 w-1.5 rounded-full transition-all duration-300 ${
                          active === s.id ? "bg-[#F29E38] scale-100" : "bg-gray-400 scale-75 group-hover:bg-[#F29E38]"
                        }`}
                      />
                      <span className={`font-trajan uppercase tracking-wider text-xs lg:text-sm transition-colors duration-300 ${
                          active === s.id ? "text-[#072D42]" : "text-[#072D42]/70 group-hover:text-[#072D42]"
                        }`}
                      >
                        {s.title}
                      </span>
                    </span>
                  </button>
                ))}
              </nav>
            </div>
          </aside>

          {/* Contenido Principal a la Derecha */}
          <section className="flex flex-col gap-12 lg:gap-16">
            {sections.map((s) => (
              <div
                key={s.id}
                id={s.id}
                ref={(el) => (refs.current[s.id] = el)}
                className="scroll-mt-28 md:scroll-mt-16"
              >
                <div
                  className={`transition-all duration-500 ${
                    visible[s.id] ? "translate-y-0 opacity-100" : "translate-y-8 opacity-0"
                  }`}
                >
                  {/* El componente AboutSection no tendrá el efecto hover */}
                  {s.id === 'about' ? (
                     <div className="rounded-2xl bg-white p-6 sm:p-8 lg:p-12 shadow-lg shadow-gray-400/10 border border-gray-200/80">
                      {s.body}
                     </div>
                  ) : (
                    // El resto de las tarjetas SÍ tendrán el efecto
                    <div className="group rounded-2xl bg-white p-6 sm:p-8 lg:p-12 shadow-lg shadow-gray-400/10 border border-gray-200/80 transition-colors duration-300 hover:bg-[#072D42]">
                      <header className="mb-4 sm:mb-6 flex items-center gap-4">
                        <s.Icon className="w-8 h-8 transition-colors duration-300 text-[#072D42] group-hover:text-white" />
                        <div>
                           <h2 className="font-bodoni text-3xl sm:text-4xl transition-colors duration-300 text-[#072D42] group-hover:text-white">
                            {s.title}
                          </h2>
                          <div className="mt-2 h-1 w-14 bg-[#F29E38] rounded-full transition-all duration-300 group-hover:w-20" />
                        </div>
                      </header>
                      <div className="text-base sm:text-lg text-[#072D42]/90 transition-colors duration-300 group-hover:text-white/90">
                        {s.body}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </section>
        </div>
      </main>
    </div>
  );
}
